queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasAirlines ?child ; p:hasAirports ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Airports } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasAirlines ?child ; p:hasAirports ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Airports } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?name2 WHERE {
  ?airports_airlines a :Airports_Airlines .
  ?airlines a :Airlines .
  ?airports_airlines p:hasAirlines ?airlines .
  ?airports a :Airports .
  ?airports_airlines p:hasAirports ?airports .
  ?airports p:name ?name .
  ?airlines p:name ?name2 .
} }
}
